// ── VAULT CRAWL CONFIG ──────────────────────────────────
// Define which vault directories to index and which to skip.
// The vault is mounted at /data/obsidian-vault on the VPS via Syncthing.
// Adjust VAULT_ROOT to match actual Syncthing destination.

const VAULT_ROOT = process.env.OBSIDIAN_VAULT_PATH || '/home/phil/SystemMac';

const INCLUDE_PATTERNS = [
  `${VAULT_ROOT}/WIKI`,
  `${VAULT_ROOT}/20_Projects/10_Recall_Agency`,
  `${VAULT_ROOT}/20_Projects/20_Reflexion_Asia`,
  `${VAULT_ROOT}/30_Knowledge/AI_Orchestration`,
  `${VAULT_ROOT}/30_Knowledge/Business`,
  `${VAULT_ROOT}/30_Knowledge/Real_Estate`,
];

const EXCLUDE_PATTERNS = [
  '.obsidian',
  '.smart-env',
  'Secrets',
  '.git',
  'node_modules',
  '.trash',
];

return [{
  json: {
    vault_root: VAULT_ROOT,
    include_patterns: INCLUDE_PATTERNS,
    exclude_patterns: EXCLUDE_PATTERNS,
    started_at: new Date().toISOString(),
    collection: 'obsidian_knowledge',
    chunk_size: 512,
    chunk_overlap: 64,
  }
}];

// ── PARSE FILE LIST ─────────────────────────────────────
// Split find output into array of file paths, deduplicate.

const stdout = $input.first().json.stdout || '';
const config = $('Vault Crawl Config').first().json;

const files = [...new Set(
  stdout.split('\n')
    .map(f => f.trim())
    .filter(f => f.endsWith('.md') && f.length > 0)
)];

if (files.length === 0) {
  return [{ json: { ...config, files: [], total_files: 0, status: 'no_changes' } }];
}

return [{ json: { ...config, files, total_files: files.length, current_file_index: 0 } }];

// ── CHUNK FILE INTO RAG SEGMENTS ────────────────────────
// Strategy:
//   1. Parse YAML frontmatter
//   2. Split on headings (#, ##, ###) as natural chunk boundaries
//   3. Each heading section becomes one chunk
//   4. Large sections are further split at 512-token target
//   5. Preserve [[wiki-links]] as metadata.internal_links
//   6. Skip files that returned __FILE_NOT_FOUND__

const raw_content = $input.first().json.stdout || '';
if (raw_content.includes('__FILE_NOT_FOUND__') || raw_content.trim().length < 50) {
  return [];
}

const file_path = $json.files;
const CHUNK_WORDS = 400;  // ~512 tokens
const OVERLAP_WORDS = 50; // ~64 tokens

// 1. Parse frontmatter
const fm_match = raw_content.match(/^---\n([\s\S]*?)\n---\n/);
let frontmatter = {};
if (fm_match) {
  const fm_lines = fm_match[1].split('\n');
  fm_lines.forEach(line => {
    const [key, ...vals] = line.split(':');
    if (key && vals.length) {
      const v = vals.join(':').trim().replace(/[\[\]'"]/g, '');
      frontmatter[key.trim()] = v;
    }
  });
}

const body = fm_match ? raw_content.slice(fm_match[0].length) : raw_content;

// 2. Extract internal links [[...]] before chunking
const wiki_links = [...body.matchAll(/\[\[([^\]]+)\]\]/g)].map(m => m[1]);

// 3. Detect brand from path or frontmatter
const detect_brand = (path) => {
  if (path.includes('10_Recall_Agency') || path.includes('recall')) return 'recall';
  if (path.includes('20_Reflexion_Asia') || path.includes('reflexion')) return 'reflexion';
  if (path.includes('WIKI')) return 'wiki';
  return frontmatter.brand || 'global';
};
const brand = detect_brand(file_path);

// 4. Split on headings
const sections = body.split(/^(#{1,3}\s+.+)$/m).filter(s => s.trim().length > 20);

// 5. Chunk each section
const chunks = [];
let current_heading = frontmatter.title || file_path.split('/').pop().replace('.md','');

for (const section of sections) {
  if (section.match(/^#{1,3}\s+/)) {
    current_heading = section.replace(/^#{1,3}\s+/, '').trim();
    continue;
  }

  const words = section.trim().split(/\s+/);
  let chunk_idx = 0;

  for (let i = 0; i < words.length; i += CHUNK_WORDS - OVERLAP_WORDS) {
    const chunk_words = words.slice(i, i + CHUNK_WORDS);
    if (chunk_words.length < 20) continue;

    const chunk_text = `# ${current_heading}\n\n${chunk_words.join(' ')}`;

    chunks.push({
      text: chunk_text,
      metadata: {
        file_path: file_path,
        vault_section: current_heading,
        frontmatter_brand: brand,
        tags: (frontmatter.tags || '').split(',').map(t => t.trim()).filter(Boolean),
        project: frontmatter.project || brand,
        heading_h1: current_heading,
        chunk_index: chunk_idx,
        internal_links: wiki_links.slice(0, 20),
        word_count: chunk_words.length,
        last_modified: frontmatter.updated || frontmatter.created || new Date().toISOString().split('T')[0],
      }
    });
    chunk_idx++;
  }
}

if (chunks.length === 0) return [];

// Pass chunks with context for the ingest call
return [{
  json: {
    file_path,
    brand,
    chunk_count: chunks.length,
    chunks,
    collection: $json.collection || 'obsidian_knowledge',
  }
}];

// ── BUILD SYNC SUMMARY ──────────────────────────────────
const items = $input.all();
const data = items[0]?.json?.data || items.map(i => i.json);

const ingested_files = Array.isArray(data) ? data.filter(d => d.ingested) : [];
const total_chunks_ingested = ingested_files.reduce((acc, d) => acc + (d.ingested?.ingested_count || 0), 0);
const total_chunks_skipped  = ingested_files.reduce((acc, d) => acc + (d.ingested?.skipped_count || 0), 0);

const brands = {};
ingested_files.forEach(d => {
  brands[d.brand || 'unknown'] = (brands[d.brand || 'unknown'] || 0) + (d.ingested?.ingested_count || 0);
});

const summary = {
  files_processed: ingested_files.length,
  chunks_new: total_chunks_ingested,
  chunks_skipped: total_chunks_skipped,
  by_brand: brands,
  completed_at: new Date().toISOString(),
};

return [{ json: { summary, stage: 'complete' } }];

const s = $json.summary;
const brandLines = Object.entries(s.by_brand || {}).map(([b, n]) => `• *${b}*: +${n} chunks`).join('\n');

return [{
  json: {
    channel: 'C023FGKE9AP',
    text: `📚 Obsidian RAG Sync complete — ${s.chunks_new} new chunks indexed`,
    blocks: [
      { type: 'section', text: { type: 'mrkdwn',
        text: `*📚 Obsidian Vault Re-indexed*\n${s.files_processed} files | +${s.chunks_new} new chunks | ${s.chunks_skipped} unchanged\n\n${brandLines}` }
      }
    ]
  }
}];
